import{_ as a,h as t}from"./chunks/theme.qLEC-07W.js";import{c as r,Q as s,j as o,m as n}from"./chunks/framework.BPKcPtvA.js";const f=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/dashboard.md","filePath":"guide/admin/dashboard.md","lastUpdated":1779094756000}'),i={name:"guide/admin/dashboard.md"};function l(d,e,h,c,u,p){return s(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h1><p>The Dashboard is the platform-wide health view that operators see first after sign-in. It is read-only — every action is a drill-down to the page where you actually do work.</p><p><img src="'+a+'" alt="Admin Dashboard" class="light-only"><img src="'+t+'" alt="Admin Dashboard" class="dark-only"></p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>The page has four bands, top to bottom.</p><h3 id="_1-summary-cards" tabindex="-1">1. Summary cards <a class="header-anchor" href="#_1-summary-cards" aria-label="Permalink to &quot;1. Summary cards&quot;">​</a></h3><p>Four headline numbers across the top:</p><ul><li><strong>Instances</strong> — total instances across the fleet.</li><li><strong>Customers</strong> — total customer accounts. <em>Hidden in focus mode.</em></li><li><strong>Tenants</strong> — total provisioned tenants.</li><li><strong>Active Jobs</strong> — currently running migration jobs (clones, deletes, imports, instance replaces).</li></ul><p>In <strong>focus mode</strong> (when you are focused on a single customer), the Customers card disappears and the other numbers narrow to the focused customer&#39;s scope.</p><h3 id="_2-instance-health" tabindex="-1">2. Instance Health <a class="header-anchor" href="#_2-instance-health" aria-label="Permalink to &quot;2. Instance Health&quot;">​</a></h3><p>A grid of instance cards. Each card shows:</p><ul><li>Instance name and region tag</li><li>Health status badge (Healthy / Degraded / Warning) with a coloured indicator</li><li>CPU, memory, and disk usage as progress bars</li><li>Tenant capacity (active / max)</li><li>P95 latency and error rate</li></ul><p>Cards are clickable — they take you to the instance detail page.</p><p>Above the grid is a filter toolbar (Environment, Region, Status) and a count chip showing filtered vs. total. A <strong>Clear All</strong> button appears when any filter is active. The &quot;View all&quot; link in the header jumps to the <a href="./instances">Instances</a> page.</p><p>Card colour reflects state: green for active, red for degraded, orange for provisioning or maintenance.</p><h3 id="_3-active-jobs-left" tabindex="-1">3. Active Jobs (left) <a class="header-anchor" href="#_3-active-jobs-left" aria-label="Permalink to &quot;3. Active Jobs (left)&quot;">​</a></h3><p>A list of migration jobs currently running. Each row shows the job type, the affected tenant, the source-to-target migration path, and a status badge. &quot;View all&quot; takes you to <a href="./migrations">Migrations</a>.</p><h3 id="_4-recent-alerts-right" tabindex="-1">4. Recent Alerts (right) <a class="header-anchor" href="#_4-recent-alerts-right" aria-label="Permalink to &quot;4. Recent Alerts (right)&quot;">​</a></h3><p>A list of recent alert events with timestamps and entity-type chips. Each row uses an icon to indicate severity (error, warning, success). &quot;View logs&quot; jumps to the <a href="./audit-log">Audit Log</a>.</p><h2 id="empty-states" tabindex="-1">Empty states <a class="header-anchor" href="#empty-states" aria-label="Permalink to &quot;Empty states&quot;">​</a></h2><p>If there are no active jobs or no recent alerts, the respective panel shows a friendly empty-state icon and message. You will see this on a quiet platform — it is not a problem.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>The Dashboard does not auto-refresh. To see the latest state, reload the page.</li><li>Health metrics are aggregated from instance heartbeats; if an instance&#39;s heartbeat is stale, its card grays out and the rolled-up numbers drop accordingly.</li><li>Sync errors on tenants are not surfaced here — drill into the affected instance to see them.</li></ul>',23)])])}const b=r(i,[["render",l]]);export{f as __pageData,b as default};
